import React, { useState } from 'react';
import { exportEmployeesXLSX, exportEmployeesCSV, exportSalaryXLSX, exportSalaryCSV } from '../services/api';
import toast from 'react-hot-toast';
import { Download, FileSpreadsheet, FileText } from 'lucide-react';

const MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];

export default function Export() {
  const [filter, setFilter] = useState({ month: '', year: '' });
  const [loading, setLoading] = useState('');

  const run = async (key, fn) => {
    setLoading(key);
    try { await fn(); toast.success('Download started!'); }
    catch { toast.error('Export failed'); }
    finally { setLoading(''); }
  };

  return (
    <div>
      <div style={s.pageHeader}>
        <div>
          <h1 style={s.title}>Export Data</h1>
          <p style={s.sub}>Download employees and salary records in XLSX or CSV format</p>
        </div>
      </div>

      {/* Employees */}
      <div style={s.card}>
        <div style={s.cardTitle}>👤 Employee Master Data</div>
        <p style={s.desc}>Export all employee records including personal, bank, and organisation details.</p>
        <div style={s.btnRow}>
          <ExportBtn icon={<FileSpreadsheet size={15}/>} label="Download XLSX" color="#1a6f3e" loading={loading==='emp-xlsx'} onClick={()=>run('emp-xlsx', exportEmployeesXLSX)}/>
          <ExportBtn icon={<FileText size={15}/>} label="Download CSV" color="#2c6fa8" loading={loading==='emp-csv'} onClick={()=>run('emp-csv', exportEmployeesCSV)}/>
        </div>
      </div>

      {/* Salary */}
      <div style={s.card}>
        <div style={s.cardTitle}>💰 Salary Records</div>
        <p style={s.desc}>Export salary records with all earnings, deductions and net pay. Optionally filter by month and year.</p>
        <div style={{ display:'flex', gap:'0.7rem', marginBottom:'1.2rem', flexWrap:'wrap' }}>
          <div>
            <label style={s.label}>Month (optional)</label>
            <select style={s.sel} value={filter.month} onChange={e=>setFilter(f=>({...f,month:e.target.value}))}>
              <option value="">All Months</option>
              {MONTHS.map(m=><option key={m}>{m}</option>)}
            </select>
          </div>
          <div>
            <label style={s.label}>Year (optional)</label>
            <select style={s.sel} value={filter.year} onChange={e=>setFilter(f=>({...f,year:e.target.value}))}>
              <option value="">All Years</option>
              {[2023,2024,2025,2026].map(y=><option key={y} value={y}>{y}</option>)}
            </select>
          </div>
        </div>
        <div style={s.btnRow}>
          <ExportBtn icon={<FileSpreadsheet size={15}/>} label="Download XLSX" color="#1a6f3e" loading={loading==='sal-xlsx'} onClick={()=>run('sal-xlsx',()=>exportSalaryXLSX(filter))}/>
          <ExportBtn icon={<FileText size={15}/>} label="Download CSV" color="#2c6fa8" loading={loading==='sal-csv'} onClick={()=>run('sal-csv',()=>exportSalaryCSV(filter))}/>
        </div>
      </div>

      <div style={s.note}>
        <strong>Note:</strong> XLSX files open directly in Microsoft Excel or Google Sheets with formatted columns and currency styling.
        CSV files are compatible with all spreadsheet applications and data tools.
      </div>
    </div>
  );
}

function ExportBtn({ icon, label, color, loading, onClick }) {
  return (
    <button style={{ ...s.exportBtn, borderColor: color, color: loading ? '#999' : color, opacity: loading ? 0.7 : 1 }} onClick={onClick} disabled={!!loading}>
      {loading ? <span style={{fontSize:'0.8rem'}}>⏳</span> : icon}
      {loading ? 'Exporting…' : label}
    </button>
  );
}

const s = {
  pageHeader:{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:'1.5rem'},
  title:{fontFamily:"'DM Serif Display',serif",fontSize:'1.8rem',color:'#0f0e0c',margin:0},
  sub:{color:'#7a7469',fontSize:'0.78rem',fontFamily:'monospace',marginTop:2},
  card:{background:'white',border:'1.5px solid #d4cfc5',borderRadius:4,padding:'1.5rem',marginBottom:'1.2rem'},
  cardTitle:{fontFamily:'monospace',fontSize:'0.68rem',textTransform:'uppercase',letterSpacing:'0.12em',color:'#c9a84c',marginBottom:'0.7rem',paddingBottom:'0.6rem',borderBottom:'1px solid #e8d5a0'},
  desc:{fontSize:'0.82rem',color:'#7a7469',marginBottom:'1.1rem',lineHeight:1.6},
  btnRow:{display:'flex',gap:'0.8rem',flexWrap:'wrap'},
  exportBtn:{display:'flex',alignItems:'center',gap:7,background:'transparent',border:'1.5px solid',borderRadius:3,padding:'0.6rem 1.3rem',fontFamily:'monospace',fontSize:'0.75rem',textTransform:'uppercase',letterSpacing:'0.08em',cursor:'pointer',fontWeight:500,transition:'all 0.15s'},
  label:{display:'block',fontFamily:'monospace',fontSize:'0.65rem',textTransform:'uppercase',letterSpacing:'0.08em',color:'#7a7469',marginBottom:'0.3rem'},
  sel:{padding:'0.45rem 0.7rem',border:'1.5px solid #d4cfc5',borderRadius:3,fontFamily:'monospace',fontSize:'0.78rem',background:'white'},
  note:{background:'#fdf9f0',border:'1.5px solid #e8d5a0',borderRadius:4,padding:'1rem 1.2rem',fontSize:'0.78rem',color:'#7a5c10',fontFamily:'monospace',lineHeight:1.7},
};
