import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './context/AuthContext';
import Layout from './components/Layout';
import Login from './pages/Login';
import Dashboard from './pages/Dashboard';
import Employees from './pages/Employees';
import Salary from './pages/Salary';
import Export from './pages/Export';
import Import from './pages/Import';
import Users from './pages/Users';
import Allowances from './pages/Allowances';
import Payout from './pages/Payout';
import FnF from './pages/FnF';
import Reports from './pages/Reports';

const qc = new QueryClient({ defaultOptions: { queries: { retry: 1, staleTime: 30000 } } });

function ProtectedRoute({ children, adminOnly }) {
  const { user, loading, isAdmin } = useAuth();
  if (loading) return <div style={{ display:'flex', alignItems:'center', justifyContent:'center', height:'100vh', fontFamily:'monospace', color:'#7a7469' }}>Loading…</div>;
  if (!user) return <Navigate to="/login" replace />;
  if (adminOnly && !isAdmin) return <Navigate to="/" replace />;
  return <Layout>{children}</Layout>;
}

export default function App() {
  return (
    <QueryClientProvider client={qc}>
      <AuthProvider>
        <BrowserRouter>
          <Toaster position="bottom-right" toastOptions={{
            style: { fontFamily: 'monospace', fontSize: '0.8rem', background: '#0f0e0c', color: '#f5f2eb', border: '1px solid #c9a84c' },
            success: { iconTheme: { primary: '#c9a84c', secondary: '#0f0e0c' } },
            error:   { iconTheme: { primary: '#b5451b', secondary: 'white' } },
          }}/>
          <Routes>
            <Route path="/login" element={<Login/>}/>
            <Route path="/" element={<ProtectedRoute><Dashboard/></ProtectedRoute>}/>
            <Route path="/employees" element={<ProtectedRoute><Employees/></ProtectedRoute>}/>
            <Route path="/salary" element={<ProtectedRoute><Salary/></ProtectedRoute>}/>
            <Route path="/allowances" element={<ProtectedRoute><Allowances/></ProtectedRoute>}/>
            <Route path="/payout" element={<ProtectedRoute><Payout/></ProtectedRoute>}/>
            <Route path="/fnf" element={<ProtectedRoute><FnF/></ProtectedRoute>}/>
            <Route path="/reports" element={<ProtectedRoute><Reports/></ProtectedRoute>}/>
            <Route path="/export" element={<ProtectedRoute><Export/></ProtectedRoute>}/>
            <Route path="/import" element={<ProtectedRoute adminOnly><Import/></ProtectedRoute>}/>
            <Route path="/users" element={<ProtectedRoute adminOnly><Users/></ProtectedRoute>}/>
            <Route path="*" element={<Navigate to="/" replace/>}/>
          </Routes>
        </BrowserRouter>
      </AuthProvider>
    </QueryClientProvider>
  );
}
