import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getUsers, createUser, toggleUser } from '../services/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Plus, X, Shield, Eye } from 'lucide-react';

export default function Users() {
  const { user: me } = useAuth();
  const qc = useQueryClient();
  const [modal, setModal] = useState(false);
  const [form, setForm] = useState({ username:'', email:'', password:'', role:'user' });

  const { data: users = [] } = useQuery({ queryKey:['users'], queryFn:()=>getUsers().then(r=>r.data) });
  const createMut = useMutation({ mutationFn: createUser, onSuccess:()=>{ toast.success('User created'); setModal(false); qc.invalidateQueries({queryKey:['users']}); }, onError: e=>toast.error(e.response?.data?.error||'Error') });
  const toggleMut = useMutation({ mutationFn: toggleUser, onSuccess:()=>{ toast.success('Updated'); qc.invalidateQueries({queryKey:['users']}); } });

  const f = k => ({ value:form[k], onChange: e=>setForm(p=>({...p,[k]:e.target.value})) });

  return (
    <div>
      <div style={s.pageHeader}>
        <div>
          <h1 style={s.title}>User Management</h1>
          <p style={s.sub}>Manage admin and viewer accounts</p>
        </div>
        <button style={s.btnPrimary} onClick={()=>setModal(true)}><Plus size={14}/> Add User</button>
      </div>

      {/* Role summary */}
      <div style={{ display:'flex', gap:'1rem', marginBottom:'1.5rem', flexWrap:'wrap' }}>
        {['admin','user'].map(role => {
          const count = users.filter(u=>u.role===role&&u.is_active).length;
          return (
            <div key={role} style={s.roleCard}>
              {role==='admin' ? <Shield size={16} style={{color:'#c9a84c'}}/> : <Eye size={16} style={{color:'#2c6fa8'}}/>}
              <span style={{fontFamily:'monospace',fontSize:'0.75rem',textTransform:'capitalize'}}>{role}s</span>
              <strong style={{fontFamily:"'DM Serif Display',serif",fontSize:'1.3rem'}}>{count}</strong>
            </div>
          );
        })}
      </div>

      <div style={s.tableWrap}>
        <table style={s.table}>
          <thead><tr>
            {['Username','Email','Role','Status','Created','Actions'].map(h=><th key={h} style={s.th}>{h}</th>)}
          </tr></thead>
          <tbody>
            {users.map((u,i)=>(
              <tr key={u.id} style={{background:i%2===0?'white':'#faf8f3'}}>
                <td style={s.td}><strong>{u.username}</strong>{u.id===me.id&&<span style={s.meTag}>You</span>}</td>
                <td style={{...s.td,...s.mono}}>{u.email}</td>
                <td style={s.td}>
                  <span style={{...s.roleBadge, ...(u.role==='admin'?s.adminBadge:s.userBadge)}}>
                    {u.role==='admin'?<Shield size={9}/>:<Eye size={9}/>} {u.role}
                  </span>
                </td>
                <td style={s.td}><span style={u.is_active?s.activeBadge:s.inactiveBadge}>{u.is_active?'Active':'Inactive'}</span></td>
                <td style={{...s.td,...s.mono}}>{new Date(u.created_at).toLocaleDateString('en-IN')}</td>
                <td style={s.td}>
                  {u.id !== me.id && (
                    <button
                      style={{...s.toggleBtn, ...(u.is_active?s.deactivateBtn:s.activateBtn)}}
                      onClick={()=>toggleMut.mutate(u.id)}
                    >
                      {u.is_active ? 'Deactivate' : 'Activate'}
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {modal && (
        <div style={s.modalOverlay} onClick={e=>e.target===e.currentTarget&&setModal(false)}>
          <div style={s.modal}>
            <div style={s.modalHeader}>
              <div style={s.modalTitle}>Create New User</div>
              <button style={s.closeBtn} onClick={()=>setModal(false)}><X size={18}/></button>
            </div>
            <div style={{padding:'1.5rem'}}>
              {[['Username','username','text'],['Email','email','email'],['Password','password','password']].map(([lbl,key,type])=>(
                <div key={key} style={{marginBottom:'1rem'}}>
                  <label style={s.label}>{lbl} *</label>
                  <input style={s.input} type={type} {...f(key)} required/>
                </div>
              ))}
              <div style={{marginBottom:'1.2rem'}}>
                <label style={s.label}>Role *</label>
                <div style={{display:'flex',gap:'1rem',marginTop:'0.5rem'}}>
                  {['user','admin'].map(r=>(
                    <label key={r} style={{display:'flex',alignItems:'center',gap:7,cursor:'pointer',fontFamily:'monospace',fontSize:'0.8rem'}}>
                      <input type="radio" name="role" value={r} checked={form.role===r} onChange={e=>setForm(p=>({...p,role:e.target.value}))}/>
                      {r==='admin'?<><Shield size={13} style={{color:'#c9a84c'}}/> Admin (Full Access)</>:<><Eye size={13} style={{color:'#2c6fa8'}}/> User (View + Export only)</>}
                    </label>
                  ))}
                </div>
              </div>
              <div style={{display:'flex',gap:'0.7rem',justifyContent:'flex-end'}}>
                <button style={s.btnSecondary} onClick={()=>setModal(false)}>Cancel</button>
                <button style={s.btnPrimary} onClick={()=>createMut.mutate(form)}>Create User</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

const s = {
  pageHeader:{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:'1.5rem',flexWrap:'wrap',gap:'1rem'},
  title:{fontFamily:"'DM Serif Display',serif",fontSize:'1.8rem',color:'#0f0e0c',margin:0},
  sub:{color:'#7a7469',fontSize:'0.78rem',fontFamily:'monospace',marginTop:2},
  roleCard:{background:'white',border:'1.5px solid #d4cfc5',borderRadius:4,padding:'0.8rem 1.2rem',display:'flex',alignItems:'center',gap:'0.6rem'},
  btnPrimary:{display:'flex',alignItems:'center',gap:5,background:'#0f0e0c',color:'#c9a84c',border:'1.5px solid #0f0e0c',borderRadius:3,padding:'0.55rem 1.1rem',fontFamily:'monospace',fontSize:'0.72rem',textTransform:'uppercase',letterSpacing:'0.08em',cursor:'pointer'},
  btnSecondary:{background:'transparent',color:'#0f0e0c',border:'1.5px solid #d4cfc5',borderRadius:3,padding:'0.55rem 1.1rem',fontFamily:'monospace',fontSize:'0.72rem',textTransform:'uppercase',letterSpacing:'0.08em',cursor:'pointer'},
  tableWrap:{border:'1.5px solid #d4cfc5',borderRadius:4,overflowX:'auto'},
  table:{width:'100%',borderCollapse:'collapse',fontSize:'0.82rem'},
  th:{background:'#0f0e0c',color:'#e8d5a0',fontFamily:'monospace',fontSize:'0.62rem',textTransform:'uppercase',letterSpacing:'0.08em',padding:'0.65rem 0.9rem',textAlign:'left'},
  td:{padding:'0.6rem 0.9rem',borderBottom:'1px solid #ede9df',verticalAlign:'middle'},
  mono:{fontFamily:'monospace',fontSize:'0.78rem'},
  meTag:{marginLeft:6,background:'#fdf3e7',border:'1px solid #e8d5a0',color:'#7a5c10',borderRadius:20,padding:'0.1rem 0.4rem',fontSize:'0.62rem',fontFamily:'monospace'},
  roleBadge:{display:'inline-flex',alignItems:'center',gap:4,borderRadius:20,padding:'0.18rem 0.55rem',fontSize:'0.65rem',fontFamily:'monospace',textTransform:'uppercase'},
  adminBadge:{background:'rgba(201,168,76,0.12)',color:'#9a7a10',border:'1px solid rgba(201,168,76,0.3)'},
  userBadge:{background:'rgba(44,111,168,0.1)',color:'#2c6fa8',border:'1px solid rgba(44,111,168,0.3)'},
  activeBadge:{background:'#d4edda',color:'#3a6b35',borderRadius:20,padding:'0.15rem 0.5rem',fontSize:'0.65rem',fontFamily:'monospace',textTransform:'uppercase'},
  inactiveBadge:{background:'#fde8e8',color:'#b5451b',borderRadius:20,padding:'0.15rem 0.5rem',fontSize:'0.65rem',fontFamily:'monospace',textTransform:'uppercase'},
  toggleBtn:{border:'1.5px solid',borderRadius:3,padding:'0.25rem 0.65rem',fontFamily:'monospace',fontSize:'0.65rem',cursor:'pointer',textTransform:'uppercase',background:'transparent'},
  deactivateBtn:{borderColor:'#b5451b',color:'#b5451b'},
  activateBtn:{borderColor:'#4a6741',color:'#4a6741'},
  modalOverlay:{position:'fixed',inset:0,background:'rgba(15,14,12,0.55)',zIndex:300,display:'flex',alignItems:'center',justifyContent:'center',padding:'1rem'},
  modal:{background:'white',border:'2px solid #d4cfc5',borderRadius:6,width:'100%',maxWidth:440,boxShadow:'0 24px 60px rgba(0,0,0,0.25)'},
  modalHeader:{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'1.2rem 1.5rem',borderBottom:'1.5px solid #d4cfc5'},
  modalTitle:{fontFamily:"'DM Serif Display',serif",fontSize:'1.2rem',color:'#0f0e0c'},
  closeBtn:{background:'none',border:'none',cursor:'pointer',color:'#7a7469',padding:4},
  label:{display:'block',fontFamily:'monospace',fontSize:'0.65rem',textTransform:'uppercase',letterSpacing:'0.08em',color:'#7a7469',marginBottom:'0.3rem'},
  input:{width:'100%',padding:'0.5rem 0.7rem',border:'1.5px solid #d4cfc5',borderRadius:3,fontFamily:"'DM Sans',sans-serif",fontSize:'0.85rem',boxSizing:'border-box',outline:'none'},
};
