import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getEmployees, createEmployee, updateEmployee, deleteEmployee } from '../services/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Plus, Edit2, Trash2, X, Search } from 'lucide-react';

const STATES = ['Andhra Pradesh','Assam','Bihar','Chhattisgarh','Delhi','Goa','Gujarat','Haryana','Himachal Pradesh','Jharkhand','Karnataka','Kerala','Madhya Pradesh','Maharashtra','Odisha','Punjab','Rajasthan','Tamil Nadu','Telangana','Uttar Pradesh','Uttarakhand','West Bengal'];
const BLANK = { emp_id:'', name:'', designation:'', client_lob:'', location:'', state:'', date_of_birth:'', sex:'', date_of_joining:'', email:'', pan_aadhaar:'', salary_mode:'', contact:'', bank_name:'', account_no:'' };

export default function Employees() {
  const { isAdmin } = useAuth();
  const qc = useQueryClient();
  const [search, setSearch] = useState('');
  const [modal, setModal] = useState(null); // null | { mode:'create'|'edit', data }
  const [form, setForm] = useState(BLANK);

  const { data: employees = [], isLoading } = useQuery({
    queryKey: ['employees', search],
    queryFn: () => getEmployees(search ? { search } : {}).then(r => r.data),
    debounce: 300,
  });

  const invalidate = () => qc.invalidateQueries({ queryKey: ['employees'] });

  const createMut = useMutation({ mutationFn: createEmployee, onSuccess: () => { toast.success('Employee created'); closeModal(); invalidate(); }, onError: e => toast.error(e.response?.data?.error || 'Error') });
  const updateMut = useMutation({ mutationFn: ({ id, data }) => updateEmployee(id, data), onSuccess: () => { toast.success('Employee updated'); closeModal(); invalidate(); }, onError: e => toast.error(e.response?.data?.error || 'Error') });
  const deleteMut = useMutation({ mutationFn: deleteEmployee, onSuccess: () => { toast.success('Employee deleted'); invalidate(); }, onError: e => toast.error(e.response?.data?.error || 'Cannot delete') });

  const openCreate = () => { setForm(BLANK); setModal({ mode: 'create' }); };
  const openEdit   = (emp) => { setForm({ ...BLANK, ...emp, date_of_birth: emp.date_of_birth?.slice(0,10)||'', date_of_joining: emp.date_of_joining?.slice(0,10)||'' }); setModal({ mode: 'edit', empId: emp.emp_id }); };
  const closeModal = () => { setModal(null); setForm(BLANK); };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (modal.mode === 'create') createMut.mutate(form);
    else updateMut.mutate({ id: modal.empId, data: form });
  };

  const f = (k) => ({ value: form[k], onChange: e => setForm(p => ({ ...p, [k]: e.target.value })) });

  return (
    <div>
      <div style={s.pageHeader}>
        <div>
          <h1 style={s.title}>Employees</h1>
          <p style={s.sub}>{employees.length} records{!isAdmin && ' · View only'}</p>
        </div>
        <div style={{ display: 'flex', gap: '0.7rem', alignItems: 'center', flexWrap: 'wrap' }}>
          <div style={s.searchWrap}>
            <Search size={14} style={{ color: '#7a7469', flexShrink: 0 }} />
            <input style={s.searchInput} placeholder="Search name, ID, designation…" value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          {isAdmin && <button style={s.btnPrimary} onClick={openCreate}><Plus size={14}/> Add Employee</button>}
        </div>
      </div>

      <div style={s.tableWrap}>
        <table style={s.table}>
          <thead><tr>
            {['Emp ID','Name','Designation','CLIENT-LOB','Location','State','DOJ','Salary Mode','Status', isAdmin ? 'Actions' : ''].map(h => h && <th key={h} style={s.th}>{h}</th>)}
          </tr></thead>
          <tbody>
            {isLoading ? (
              <tr><td colSpan={10} style={s.empty}>Loading…</td></tr>
            ) : !employees.length ? (
              <tr><td colSpan={10} style={s.empty}>No employees found.</td></tr>
            ) : employees.map((e, i) => (
              <tr key={e.emp_id} style={{ background: i%2===0 ? 'white' : '#faf8f3' }}>
                <td style={{...s.td,...s.mono}}>{e.emp_id}</td>
                <td style={s.td}><strong>{e.name}</strong></td>
                <td style={s.td}>{e.designation||'—'}</td>
                <td style={s.td}>{e.client_lob||'—'}</td>
                <td style={s.td}>{e.location||'—'}</td>
                <td style={s.td}>{e.state||'—'}</td>
                <td style={{...s.td,...s.mono}}>{e.date_of_joining?.slice(0,10)||'—'}</td>
                <td style={s.td}>{e.salary_mode||'—'}</td>
                <td style={s.td}><span style={e.is_active ? s.badgeActive : s.badgeInactive}>{e.is_active ? 'Active' : 'Inactive'}</span></td>
                {isAdmin && (
                  <td style={{...s.td, whiteSpace:'nowrap'}}>
                    <button style={s.btnSm} onClick={() => openEdit(e)}><Edit2 size={12}/></button>
                    <button style={{...s.btnSm,...s.btnDanger}} onClick={() => { if(window.confirm('Delete this employee?')) deleteMut.mutate(e.emp_id); }}><Trash2 size={12}/></button>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Modal */}
      {modal && (
        <div style={s.modalOverlay} onClick={e => e.target === e.currentTarget && closeModal()}>
          <div style={s.modal}>
            <div style={s.modalHeader}>
              <div style={s.modalTitle}>{modal.mode === 'create' ? 'Add Employee' : 'Edit Employee'}</div>
              <button style={s.closeBtn} onClick={closeModal}><X size={18}/></button>
            </div>
            <form onSubmit={handleSubmit} style={{ overflowY: 'auto', maxHeight: 'calc(90vh - 120px)', padding: '0 1.5rem 1.5rem' }}>
              <Section title="Personal Info">
                <Row><Field label="Emp ID *" disabled={modal.mode==='edit'} {...f('emp_id')} required/><Field label="Full Name *" {...f('name')} required/></Row>
                <Row><Field label="Date of Birth" type="date" {...f('date_of_birth')}/><Sel label="Sex" {...f('sex')} opts={['Male','Female','Other']}/></Row>
                <Row><Field label="Contact No" {...f('contact')}/><Field label="Email" type="email" {...f('email')}/></Row>
                <Row><Field label="PAN / Aadhaar" {...f('pan_aadhaar')}/><Field label="Date of Joining" type="date" {...f('date_of_joining')}/></Row>
              </Section>
              <Section title="Organisation">
                <Row><Field label="Designation" {...f('designation')}/><Field label="CLIENT-LOB" {...f('client_lob')}/></Row>
                <Row><Field label="Location" {...f('location')}/><Sel label="State" {...f('state')} opts={STATES}/></Row>
                <Row><Sel label="Salary Mode" {...f('salary_mode')} opts={['Bank Transfer','Cash','Cheque']}/></Row>
              </Section>
              <Section title="Bank Details">
                <Row><Field label="Bank Name" {...f('bank_name')}/><Field label="Account No" {...f('account_no')}/></Row>
              </Section>
              <div style={{ display:'flex', gap:'0.7rem', justifyContent:'flex-end', marginTop:'1rem' }}>
                <button type="button" style={s.btnSecondary} onClick={closeModal}>Cancel</button>
                <button type="submit" style={s.btnPrimary}>{modal.mode==='create' ? 'Create Employee' : 'Save Changes'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

const Section = ({ title, children }) => (
  <div style={{ marginBottom:'1.2rem' }}>
    <div style={{ fontFamily:'monospace', fontSize:'0.65rem', textTransform:'uppercase', letterSpacing:'0.1em', color:'#c9a84c', marginBottom:'0.8rem', paddingBottom:'0.4rem', borderBottom:'1px solid #e8d5a0' }}>{title}</div>
    {children}
  </div>
);
const Row = ({ children }) => <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'0.8rem', marginBottom:'0.8rem' }}>{children}</div>;
const Field = ({ label, ...props }) => (
  <div><label style={s.label}>{label}</label><input style={s.input} {...props}/></div>
);
const Sel = ({ label, opts, ...props }) => (
  <div><label style={s.label}>{label}</label>
    <select style={s.input} {...props}>
      <option value="">Select</option>
      {opts.map(o => <option key={o} value={o}>{o}</option>)}
    </select>
  </div>
);

const s = {
  pageHeader: { display:'flex', alignItems:'flex-start', justifyContent:'space-between', marginBottom:'1.5rem', flexWrap:'wrap', gap:'1rem' },
  title: { fontFamily:"'DM Serif Display',serif", fontSize:'1.8rem', color:'#0f0e0c', margin:0 },
  sub: { color:'#7a7469', fontSize:'0.78rem', fontFamily:'monospace', marginTop:2 },
  searchWrap: { display:'flex', alignItems:'center', gap:6, background:'white', border:'1.5px solid #d4cfc5', borderRadius:3, padding:'0.4rem 0.7rem', minWidth:240 },
  searchInput: { border:'none', outline:'none', fontFamily:'monospace', fontSize:'0.8rem', width:'100%', background:'transparent' },
  btnPrimary: { display:'flex', alignItems:'center', gap:5, background:'#0f0e0c', color:'#c9a84c', border:'1.5px solid #0f0e0c', borderRadius:3, padding:'0.55rem 1.1rem', fontFamily:'monospace', fontSize:'0.72rem', textTransform:'uppercase', letterSpacing:'0.08em', cursor:'pointer' },
  btnSecondary: { background:'transparent', color:'#0f0e0c', border:'1.5px solid #d4cfc5', borderRadius:3, padding:'0.55rem 1.1rem', fontFamily:'monospace', fontSize:'0.72rem', textTransform:'uppercase', letterSpacing:'0.08em', cursor:'pointer' },
  btnSm: { background:'transparent', border:'1.5px solid #d4cfc5', borderRadius:3, padding:'0.25rem 0.4rem', cursor:'pointer', marginRight:4 },
  btnDanger: { borderColor:'#b5451b', color:'#b5451b' },
  tableWrap: { border:'1.5px solid #d4cfc5', borderRadius:4, overflowX:'auto' },
  table: { width:'100%', borderCollapse:'collapse', fontSize:'0.8rem' },
  th: { background:'#0f0e0c', color:'#e8d5a0', fontFamily:'monospace', fontSize:'0.62rem', textTransform:'uppercase', letterSpacing:'0.08em', padding:'0.65rem 0.9rem', textAlign:'left', whiteSpace:'nowrap' },
  td: { padding:'0.55rem 0.9rem', borderBottom:'1px solid #ede9df', verticalAlign:'middle' },
  mono: { fontFamily:'monospace', fontSize:'0.78rem' },
  badgeActive: { background:'#d4edda', color:'#3a6b35', borderRadius:20, padding:'0.15rem 0.5rem', fontSize:'0.65rem', fontFamily:'monospace', textTransform:'uppercase' },
  badgeInactive: { background:'#fde8e8', color:'#b5451b', borderRadius:20, padding:'0.15rem 0.5rem', fontSize:'0.65rem', fontFamily:'monospace', textTransform:'uppercase' },
  empty: { textAlign:'center', padding:'2.5rem', color:'#7a7469', fontFamily:'monospace', fontSize:'0.8rem' },
  modalOverlay: { position:'fixed', inset:0, background:'rgba(15,14,12,0.55)', zIndex:300, display:'flex', alignItems:'center', justifyContent:'center', padding:'1rem' },
  modal: { background:'white', border:'2px solid #d4cfc5', borderRadius:6, width:'100%', maxWidth:640, maxHeight:'90vh', display:'flex', flexDirection:'column', boxShadow:'0 24px 60px rgba(0,0,0,0.25)' },
  modalHeader: { display:'flex', alignItems:'center', justifyContent:'space-between', padding:'1.2rem 1.5rem', borderBottom:'1.5px solid #d4cfc5', flexShrink:0 },
  modalTitle: { fontFamily:"'DM Serif Display',serif", fontSize:'1.2rem', color:'#0f0e0c' },
  closeBtn: { background:'none', border:'none', cursor:'pointer', color:'#7a7469', padding:4 },
  label: { display:'block', fontFamily:'monospace', fontSize:'0.65rem', textTransform:'uppercase', letterSpacing:'0.08em', color:'#7a7469', marginBottom:'0.3rem' },
  input: { width:'100%', padding:'0.5rem 0.7rem', border:'1.5px solid #d4cfc5', borderRadius:3, fontFamily:"'DM Sans',sans-serif", fontSize:'0.85rem', boxSizing:'border-box', outline:'none' },
};
