// ── EXPORT ───────────────────────────────────────────────────────────────────
const download = async (url, filename, params = {}) => {
  const res = await api.get(url, { params, responseType: 'blob' });
  const href = URL.createObjectURL(res.data);
  const a = document.createElement('a');
  a.href = href; a.download = filename; a.click();
  URL.revokeObjectURL(href);
};

export const exportEmployeesXLSX = () => download('/export/employees/xlsx', 'employees.xlsx');
export const exportEmployeesCSV  = () => download('/export/employees/csv',  'employees.csv');
export const exportSalaryXLSX = (params) => download('/export/salary/xlsx', `salary_${params?.month||'all'}_${params?.year||'all'}.xlsx`, params);
export const exportSalaryCSV  = (params) => download('/export/salary/csv',  'salary_export.csv', params);

export const downloadEmpTemplate    = () => download('/templates/employees', 'employees_template.xlsx');
export const downloadSalaryTemplate = () => download('/templates/salary',    'salary_template.xlsx');

// ── IMPORT ───────────────────────────────────────────────────────────────────
export const importEmployees = (file) => {
  const fd = new FormData(); fd.append('file', file);
  return api.post('/import/employees', fd, { headers: { 'Content-Type': 'multipart/form-data' } });
};
