import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import {
  getAllowanceTypes, createAllowanceType, updateAllowanceType, deleteAllowanceType,
  getAllowances, getEmployees, assignAllowance, deleteAllowance, getAllowanceSummary
} from '../services/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Plus, X, Trash2, Edit2, Percent, DollarSign, Tag } from 'lucide-react';

const fmt = n => '₹' + Number(n||0).toLocaleString('en-IN', { minimumFractionDigits: 2 });

export default function Allowances() {
  const { isAdmin } = useAuth();
  const qc = useQueryClient();
  const [tab, setTab] = useState('types'); // 'types' | 'assignments' | 'summary'
  const [typeModal, setTypeModal]   = useState(null);
  const [assignModal, setAssignModal] = useState(false);
  const [typeForm, setTypeForm]     = useState({ name:'', code:'', calc_type:'fixed', default_value:'', description:'', is_taxable:false });
  const [assignForm, setAssignForm] = useState({ emp_id:'', allowance_type_id:'', calc_type:'fixed', value:'', effective_from:'', effective_to:'', remarks:'' });
  const [empFilter, setEmpFilter]   = useState('');

  const { data: types=[] }   = useQuery({ queryKey:['allowance-types'], queryFn:()=>getAllowanceTypes().then(r=>r.data) });
  const { data: employees=[] } = useQuery({ queryKey:['employees'], queryFn:()=>getEmployees().then(r=>r.data) });
  const { data: assignments=[] } = useQuery({ queryKey:['allowances', empFilter], queryFn:()=>getAllowances(empFilter?{emp_id:empFilter}:{}).then(r=>r.data) });
  const { data: summary=[] }  = useQuery({ queryKey:['allowance-summary'], queryFn:()=>getAllowanceSummary().then(r=>r.data) });

  const invalidateAll = () => { qc.invalidateQueries({queryKey:['allowance-types']}); qc.invalidateQueries({queryKey:['allowances']}); qc.invalidateQueries({queryKey:['allowance-summary']}); };

  const createTypeMut = useMutation({ mutationFn: createAllowanceType, onSuccess:()=>{ toast.success('Type created'); setTypeModal(null); invalidateAll(); }, onError:e=>toast.error(e.response?.data?.error||'Error') });
  const updateTypeMut = useMutation({ mutationFn:({id,data})=>updateAllowanceType(id,data), onSuccess:()=>{ toast.success('Updated'); setTypeModal(null); invalidateAll(); }, onError:e=>toast.error(e.response?.data?.error||'Error') });
  const deleteTypeMut = useMutation({ mutationFn: deleteAllowanceType, onSuccess:()=>{ toast.success('Deactivated'); invalidateAll(); } });
  const assignMut     = useMutation({ mutationFn: assignAllowance, onSuccess:()=>{ toast.success('Allowance assigned'); setAssignModal(false); setAssignForm({emp_id:'',allowance_type_id:'',calc_type:'fixed',value:'',effective_from:'',effective_to:'',remarks:''}); invalidateAll(); }, onError:e=>toast.error(e.response?.data?.error||'Error') });
  const deleteAssignMut = useMutation({ mutationFn: deleteAllowance, onSuccess:()=>{ toast.success('Removed'); invalidateAll(); } });

  const openEditType = (t) => { setTypeForm({ name:t.name, code:t.code, calc_type:t.calc_type, default_value:t.default_value, description:t.description||'', is_taxable:t.is_taxable }); setTypeModal({ mode:'edit', id:t.id }); };
  const openCreateType = () => { setTypeForm({ name:'', code:'', calc_type:'fixed', default_value:'', description:'', is_taxable:false }); setTypeModal({ mode:'create' }); };

  const tf = k => ({ value: typeForm[k], onChange: e => setTypeForm(p=>({...p,[k]:e.target.value})) });
  const af = k => ({ value: assignForm[k], onChange: e => setAssignForm(p=>({...p,[k]:e.target.value})) });

  const selectedType = types.find(t=>t.id===parseInt(assignForm.allowance_type_id));

  return (
    <div>
      <div style={s.pageHeader}>
        <div>
          <h1 style={s.title}>Allowances</h1>
          <p style={s.sub}>Manage allowance types and employee assignments</p>
        </div>
        {isAdmin && (
          <div style={{ display:'flex', gap:'0.7rem' }}>
            {tab==='types' && <button style={s.btnPrimary} onClick={openCreateType}><Plus size={13}/> New Type</button>}
            {tab==='assignments' && <button style={s.btnPrimary} onClick={()=>setAssignModal(true)}><Plus size={13}/> Assign Allowance</button>}
          </div>
        )}
      </div>

      {/* Tabs */}
      <div style={s.tabs}>
        {[['types','Allowance Types'],['assignments','Employee Assignments'],['summary','Summary']].map(([k,l])=>(
          <button key={k} style={{...s.tabBtn,...(tab===k?s.tabActive:{})}} onClick={()=>setTab(k)}>{l}</button>
        ))}
      </div>

      {/* TYPES TAB */}
      {tab==='types' && (
        <div style={s.tableWrap}>
          <table style={s.table}>
            <thead><tr>{['Code','Name','Type','Default Value','Taxable','Status','Actions'].map(h=><th key={h} style={s.th}>{h}</th>)}</tr></thead>
            <tbody>
              {!types.length ? <tr><td colSpan={7} style={s.empty}>No allowance types yet. Click "New Type" to create one.</td></tr>
              : types.map((t,i)=>(
                <tr key={t.id} style={{background:i%2===0?'white':'#faf8f3'}}>
                  <td style={{...s.td,...s.mono}}><span style={s.codeTag}>{t.code}</span></td>
                  <td style={s.td}><strong>{t.name}</strong>{t.description&&<div style={{fontSize:'0.72rem',color:'#7a7469',marginTop:2}}>{t.description}</div>}</td>
                  <td style={s.td}><span style={{...s.badge,...(t.calc_type==='percent'?s.pctBadge:s.fixedBadge)}}>{t.calc_type==='percent'?<><Percent size={9}/> Percent</>:<><DollarSign size={9}/> Fixed</>}</span></td>
                  <td style={{...s.td,...s.mono}}>{t.calc_type==='percent'?`${t.default_value}%`:fmt(t.default_value)}</td>
                  <td style={s.td}><span style={t.is_taxable?s.badgeRed:s.badgeGreen}>{t.is_taxable?'Taxable':'Non-taxable'}</span></td>
                  <td style={s.td}><span style={t.is_active?s.badgeGreen:s.badgeRed}>{t.is_active?'Active':'Inactive'}</span></td>
                  <td style={s.td}>
                    {isAdmin && <>
                      <button style={s.btnSm} onClick={()=>openEditType(t)}><Edit2 size={12}/></button>
                      <button style={{...s.btnSm,borderColor:'#b5451b',color:'#b5451b'}} onClick={()=>{if(window.confirm('Deactivate?'))deleteTypeMut.mutate(t.id)}}><Trash2 size={12}/></button>
                    </>}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* ASSIGNMENTS TAB */}
      {tab==='assignments' && (
        <>
          <div style={{ marginBottom:'1rem', display:'flex', gap:'0.7rem', alignItems:'center' }}>
            <label style={s.label}>Filter by Employee</label>
            <select style={s.sel} value={empFilter} onChange={e=>setEmpFilter(e.target.value)}>
              <option value="">All Employees</option>
              {employees.map(e=><option key={e.emp_id} value={e.emp_id}>{e.emp_id} – {e.name}</option>)}
            </select>
          </div>
          <div style={s.tableWrap}>
            <table style={s.table}>
              <thead><tr>{['Employee','Allowance Type','Calc Type','Value','Computed Amt','Effective From','Effective To','Status',isAdmin?'Action':''].map((h,i)=>h&&<th key={i} style={s.th}>{h}</th>)}</tr></thead>
              <tbody>
                {!assignments.length ? <tr><td colSpan={9} style={s.empty}>No allowances assigned yet.</td></tr>
                : assignments.map((a,i)=>(
                  <tr key={a.id} style={{background:i%2===0?'white':'#faf8f3'}}>
                    <td style={s.td}><strong>{a.emp_name}</strong><div style={{fontSize:'0.7rem',color:'#7a7469',fontFamily:'monospace'}}>{a.emp_id}</div></td>
                    <td style={s.td}><span style={s.codeTag}>{a.code}</span><div style={{fontSize:'0.75rem',marginTop:2}}>{a.type_name}</div></td>
                    <td style={s.td}><span style={{...s.badge,...(a.calc_type==='percent'?s.pctBadge:s.fixedBadge)}}>{a.calc_type}</span></td>
                    <td style={{...s.td,...s.mono}}>{a.calc_type==='percent'?`${a.value}%`:fmt(a.value)}</td>
                    <td style={{...s.td,...s.mono,color:'#4a6741',fontWeight:600}}>{a.computed_amount?fmt(a.computed_amount):'—'}</td>
                    <td style={{...s.td,...s.mono}}>{a.effective_from?.slice(0,10)||'—'}</td>
                    <td style={{...s.td,...s.mono}}>{a.effective_to?.slice(0,10)||'Ongoing'}</td>
                    <td style={s.td}><span style={a.is_active?s.badgeGreen:s.badgeRed}>{a.is_active?'Active':'Inactive'}</span></td>
                    {isAdmin && <td style={s.td}><button style={{...s.btnSm,borderColor:'#b5451b',color:'#b5451b'}} onClick={()=>{if(window.confirm('Remove?'))deleteAssignMut.mutate(a.id)}}><Trash2 size={12}/></button></td>}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      )}

      {/* SUMMARY TAB */}
      {tab==='summary' && (
        <div style={s.tableWrap}>
          <table style={s.table}>
            <thead><tr>{['Allowance Type','Code','Calc Type','Employees Assigned','Total Fixed / Avg %'].map(h=><th key={h} style={s.th}>{h}</th>)}</tr></thead>
            <tbody>
              {!summary.length ? <tr><td colSpan={5} style={s.empty}>No data yet.</td></tr>
              : summary.map((r,i)=>(
                <tr key={i} style={{background:i%2===0?'white':'#faf8f3'}}>
                  <td style={s.td}><strong>{r.type_name}</strong></td>
                  <td style={s.td}><span style={s.codeTag}>{r.code}</span></td>
                  <td style={s.td}><span style={{...s.badge,...(r.calc_type==='percent'?s.pctBadge:s.fixedBadge)}}>{r.calc_type}</span></td>
                  <td style={{...s.td,...s.mono}}>{r.emp_count}</td>
                  <td style={{...s.td,...s.mono}}>{r.calc_type==='fixed'?fmt(r.total_fixed):`Avg ${parseFloat(r.avg_percent||0).toFixed(1)}%`}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* TYPE MODAL */}
      {typeModal && (
        <div style={s.overlay} onClick={e=>e.target===e.currentTarget&&setTypeModal(null)}>
          <div style={s.modal}>
            <div style={s.modalHdr}><span style={s.modalTitle}>{typeModal.mode==='create'?'New Allowance Type':'Edit Allowance Type'}</span><button style={s.closeBtn} onClick={()=>setTypeModal(null)}><X size={18}/></button></div>
            <div style={s.modalBody}>
              <Grid2>
                <Field label="Name *"><input style={s.input} {...tf('name')} required/></Field>
                <Field label="Code *"><input style={s.input} {...tf('code')} placeholder="e.g. TRANSPORT" disabled={typeModal.mode==='edit'}/></Field>
              </Grid2>
              <Grid2>
                <Field label="Calculation Type *">
                  <select style={s.input} {...tf('calc_type')}>
                    <option value="fixed">Fixed Amount (₹)</option>
                    <option value="percent">% of Basic Salary</option>
                  </select>
                </Field>
                <Field label={typeForm.calc_type==='percent'?'Default % Value':'Default ₹ Amount'}>
                  <input style={s.input} type="number" min="0" step="0.01" {...tf('default_value')}/>
                </Field>
              </Grid2>
              <Field label="Description"><input style={s.input} {...tf('description')} placeholder="Optional"/></Field>
              <label style={{ display:'flex', alignItems:'center', gap:8, cursor:'pointer', marginTop:'0.8rem', fontFamily:'monospace', fontSize:'0.78rem' }}>
                <input type="checkbox" checked={typeForm.is_taxable} onChange={e=>setTypeForm(p=>({...p,is_taxable:e.target.checked}))}/>
                Mark as Taxable
              </label>
              <div style={s.modalFooter}>
                <button style={s.btnSecondary} onClick={()=>setTypeModal(null)}>Cancel</button>
                <button style={s.btnPrimary} onClick={()=> typeModal.mode==='create'?createTypeMut.mutate(typeForm):updateTypeMut.mutate({id:typeModal.id,data:typeForm})}>
                  {typeModal.mode==='create'?'Create Type':'Save Changes'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ASSIGN MODAL */}
      {assignModal && (
        <div style={s.overlay} onClick={e=>e.target===e.currentTarget&&setAssignModal(false)}>
          <div style={s.modal}>
            <div style={s.modalHdr}><span style={s.modalTitle}>Assign Allowance to Employee</span><button style={s.closeBtn} onClick={()=>setAssignModal(false)}><X size={18}/></button></div>
            <div style={s.modalBody}>
              <Grid2>
                <Field label="Employee *">
                  <select style={s.input} {...af('emp_id')} required>
                    <option value="">Select</option>
                    {employees.map(e=><option key={e.emp_id} value={e.emp_id}>{e.emp_id} – {e.name}</option>)}
                  </select>
                </Field>
                <Field label="Allowance Type *">
                  <select style={s.input} {...af('allowance_type_id')} onChange={e=>{ const t=types.find(x=>x.id===parseInt(e.target.value)); setAssignForm(p=>({...p,allowance_type_id:e.target.value,calc_type:t?.calc_type||'fixed',value:t?.default_value||''})); }}>
                    <option value="">Select</option>
                    {types.filter(t=>t.is_active).map(t=><option key={t.id} value={t.id}>{t.name} ({t.code})</option>)}
                  </select>
                </Field>
              </Grid2>
              <Grid2>
                <Field label="Calculation Type *">
                  <select style={s.input} {...af('calc_type')}>
                    <option value="fixed">Fixed Amount (₹)</option>
                    <option value="percent">% of Basic Salary</option>
                  </select>
                </Field>
                <Field label={assignForm.calc_type==='percent'?'% Value *':'Amount (₹) *'}>
                  <input style={s.input} type="number" min="0" step="0.01" {...af('value')} required/>
                </Field>
              </Grid2>
              <Grid2>
                <Field label="Effective From"><input style={s.input} type="date" {...af('effective_from')}/></Field>
                <Field label="Effective To (optional)"><input style={s.input} type="date" {...af('effective_to')}/></Field>
              </Grid2>
              <Field label="Remarks"><input style={s.input} {...af('remarks')} placeholder="Optional"/></Field>
              <div style={s.modalFooter}>
                <button style={s.btnSecondary} onClick={()=>setAssignModal(false)}>Cancel</button>
                <button style={s.btnPrimary} onClick={()=>assignMut.mutate(assignForm)}>Assign Allowance</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

const Grid2 = ({children}) => <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'0.9rem',marginBottom:'0.9rem'}}>{children}</div>;
const Field = ({label,children}) => <div><label style={s.label}>{label}</label>{children}</div>;

const s = {
  pageHeader:{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:'1.5rem',flexWrap:'wrap',gap:'1rem'},
  title:{fontFamily:"'DM Serif Display',serif",fontSize:'1.8rem',color:'#0f0e0c',margin:0},
  sub:{color:'#7a7469',fontSize:'0.78rem',fontFamily:'monospace',marginTop:2},
  tabs:{display:'flex',gap:0,borderBottom:'2px solid #d4cfc5',marginBottom:'1.5rem'},
  tabBtn:{background:'none',border:'none',borderBottom:'3px solid transparent',padding:'0.7rem 1.4rem',fontFamily:'monospace',fontSize:'0.75rem',textTransform:'uppercase',letterSpacing:'0.08em',cursor:'pointer',color:'#7a7469',marginBottom:'-2px'},
  tabActive:{color:'#0f0e0c',borderBottomColor:'#c9a84c',background:'white'},
  tableWrap:{border:'1.5px solid #d4cfc5',borderRadius:4,overflowX:'auto'},
  table:{width:'100%',borderCollapse:'collapse',fontSize:'0.8rem'},
  th:{background:'#0f0e0c',color:'#e8d5a0',fontFamily:'monospace',fontSize:'0.62rem',textTransform:'uppercase',letterSpacing:'0.08em',padding:'0.65rem 0.9rem',textAlign:'left',whiteSpace:'nowrap'},
  td:{padding:'0.55rem 0.9rem',borderBottom:'1px solid #ede9df',verticalAlign:'middle'},
  mono:{fontFamily:'monospace',fontSize:'0.78rem'},
  badge:{display:'inline-flex',alignItems:'center',gap:4,borderRadius:20,padding:'0.15rem 0.5rem',fontSize:'0.65rem',fontFamily:'monospace',textTransform:'uppercase'},
  pctBadge:{background:'rgba(44,111,168,0.1)',color:'#2c6fa8',border:'1px solid rgba(44,111,168,0.3)'},
  fixedBadge:{background:'rgba(74,103,65,0.1)',color:'#4a6741',border:'1px solid rgba(74,103,65,0.3)'},
  badgeGreen:{background:'#d4edda',color:'#3a6b35',borderRadius:20,padding:'0.15rem 0.5rem',fontSize:'0.65rem',fontFamily:'monospace'},
  badgeRed:{background:'#fde8e8',color:'#b5451b',borderRadius:20,padding:'0.15rem 0.5rem',fontSize:'0.65rem',fontFamily:'monospace'},
  codeTag:{background:'#f5f2eb',border:'1px solid #d4cfc5',borderRadius:3,padding:'0.1rem 0.4rem',fontFamily:'monospace',fontSize:'0.72rem',fontWeight:600},
  sel:{padding:'0.45rem 0.7rem',border:'1.5px solid #d4cfc5',borderRadius:3,fontFamily:'monospace',fontSize:'0.78rem',background:'white'},
  btnPrimary:{display:'flex',alignItems:'center',gap:5,background:'#0f0e0c',color:'#c9a84c',border:'1.5px solid #0f0e0c',borderRadius:3,padding:'0.55rem 1.1rem',fontFamily:'monospace',fontSize:'0.72rem',textTransform:'uppercase',letterSpacing:'0.08em',cursor:'pointer'},
  btnSecondary:{background:'transparent',color:'#0f0e0c',border:'1.5px solid #d4cfc5',borderRadius:3,padding:'0.55rem 1.1rem',fontFamily:'monospace',fontSize:'0.72rem',textTransform:'uppercase',cursor:'pointer'},
  btnSm:{background:'transparent',border:'1.5px solid #d4cfc5',borderRadius:3,padding:'0.25rem 0.4rem',cursor:'pointer',marginRight:4},
  overlay:{position:'fixed',inset:0,background:'rgba(15,14,12,0.55)',zIndex:300,display:'flex',alignItems:'center',justifyContent:'center',padding:'1rem'},
  modal:{background:'white',border:'2px solid #d4cfc5',borderRadius:6,width:'100%',maxWidth:580,maxHeight:'90vh',display:'flex',flexDirection:'column',boxShadow:'0 24px 60px rgba(0,0,0,0.25)'},
  modalHdr:{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'1.2rem 1.5rem',borderBottom:'1.5px solid #d4cfc5'},
  modalTitle:{fontFamily:"'DM Serif Display',serif",fontSize:'1.15rem',color:'#0f0e0c'},
  modalBody:{padding:'1.5rem',overflowY:'auto'},
  modalFooter:{display:'flex',gap:'0.7rem',justifyContent:'flex-end',marginTop:'1.2rem'},
  closeBtn:{background:'none',border:'none',cursor:'pointer',color:'#7a7469',padding:4},
  label:{display:'block',fontFamily:'monospace',fontSize:'0.65rem',textTransform:'uppercase',letterSpacing:'0.08em',color:'#7a7469',marginBottom:'0.3rem'},
  input:{width:'100%',padding:'0.5rem 0.7rem',border:'1.5px solid #d4cfc5',borderRadius:3,fontFamily:"'DM Sans',sans-serif",fontSize:'0.85rem',boxSizing:'border-box'},
  empty:{textAlign:'center',padding:'2.5rem',color:'#7a7469',fontFamily:'monospace',fontSize:'0.8rem'},
};
