import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getPayouts, getPayoutSummary, generatePayouts, updatePayoutStatus, bulkUpdatePayoutStatus, deletePayout } from '../services/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Zap, CheckCircle, DollarSign, Clock, X, ChevronDown } from 'lucide-react';

const MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const fmt = n => '₹' + Number(n||0).toLocaleString('en-IN', { minimumFractionDigits:2 });
const STATUS_COLORS = { pending:'#c9a84c', processed:'#2c6fa8', paid:'#4a6741' };
const STATUS_BG     = { pending:'#fdf9f0', processed:'#e8f0f8', paid:'#edf5ec' };

export default function Payout() {
  const { isAdmin } = useAuth();
  const qc = useQueryClient();
  const [filter, setFilter] = useState({ month: MONTHS[new Date().getMonth()], year: new Date().getFullYear().toString(), status: '' });
  const [tab, setTab]           = useState('list'); // 'list' | 'history'
  const [genModal, setGenModal]  = useState(false);
  const [genForm, setGenForm]    = useState({ month: MONTHS[new Date().getMonth()], year: new Date().getFullYear().toString() });
  const [statusModal, setStatusModal] = useState(null); // { payout, targetStatus }
  const [statusForm, setStatusForm]   = useState({ payment_date:'', reference_no:'', payout_mode:'bank_transfer', remarks:'' });
  const [selected, setSelected]  = useState([]);

  const { data: payouts=[], isLoading } = useQuery({
    queryKey: ['payouts', filter],
    queryFn: () => getPayouts(filter).then(r=>r.data)
  });
  const { data: summary } = useQuery({
    queryKey: ['payout-summary'],
    queryFn: () => getPayoutSummary().then(r=>r.data)
  });

  const inv = () => { qc.invalidateQueries({queryKey:['payouts']}); qc.invalidateQueries({queryKey:['payout-summary']}); };

  const genMut    = useMutation({ mutationFn: generatePayouts, onSuccess: r=>{ toast.success(r.data.message); setGenModal(false); inv(); }, onError:e=>toast.error(e.response?.data?.error||'Error') });
  const statusMut = useMutation({ mutationFn:({id,data})=>updatePayoutStatus(id,data), onSuccess:()=>{ toast.success('Status updated'); setStatusModal(null); inv(); }, onError:e=>toast.error(e.response?.data?.error||'Error') });
  const bulkMut   = useMutation({ mutationFn: bulkUpdatePayoutStatus, onSuccess: r=>{ toast.success(r.data.message); setSelected([]); inv(); }, onError:e=>toast.error(e.response?.data?.error||'Error') });
  const delMut    = useMutation({ mutationFn: deletePayout, onSuccess:()=>{ toast.success('Deleted'); inv(); }, onError:e=>toast.error(e.response?.data?.error||'Error') });

  const openStatusModal = (payout, targetStatus) => {
    setStatusForm({ payment_date:'', reference_no:'', payout_mode: payout.payout_mode||'bank_transfer', remarks:'' });
    setStatusModal({ payout, targetStatus });
  };

  const toggleSelect = (id) => setSelected(p => p.includes(id) ? p.filter(x=>x!==id) : [...p,id]);
  const allSelected  = payouts.length > 0 && selected.length === payouts.length;

  const stats = summary?.byStatus || [];
  const getStatCount = (st) => stats.find(s=>s.status===st)?.count||0;
  const getStatAmt   = (st) => stats.find(s=>s.status===st)?.total||0;

  return (
    <div>
      <div style={s.pageHeader}>
        <div>
          <h1 style={s.title}>Payout</h1>
          <p style={s.sub}>Monthly salary disbursement tracking</p>
        </div>
        {isAdmin && <button style={s.btnPrimary} onClick={()=>setGenModal(true)}><Zap size={14}/> Generate Payouts</button>}
      </div>

      {/* Stat cards */}
      <div style={s.statRow}>
        {[['pending','Pending',Clock],['processed','Processed',ChevronDown],['paid','Paid',CheckCircle]].map(([st,lbl,Icon])=>(
          <div key={st} style={{...s.statCard, borderTop:`3px solid ${STATUS_COLORS[st]}`}}>
            <div style={{color:STATUS_COLORS[st],marginBottom:4}}><Icon size={16}/></div>
            <div style={s.statLabel}>{lbl}</div>
            <div style={{...s.statVal,color:STATUS_COLORS[st]}}>{getStatCount(st)}</div>
            <div style={{fontFamily:'monospace',fontSize:'0.72rem',color:'#7a7469',marginTop:2}}>{fmt(getStatAmt(st))}</div>
          </div>
        ))}
        <div style={{...s.statCard,borderTop:'3px solid #0f0e0c'}}>
          <div style={{color:'#c9a84c',marginBottom:4}}><DollarSign size={16}/></div>
          <div style={s.statLabel}>Total Payroll</div>
          <div style={{...s.statVal,color:'#0f0e0c'}}>{fmt(stats.reduce((a,r)=>a+parseFloat(r.total||0),0))}</div>
          <div style={{fontFamily:'monospace',fontSize:'0.72rem',color:'#7a7469',marginTop:2}}>{stats.reduce((a,r)=>a+parseInt(r.count||0),0)} records</div>
        </div>
      </div>

      {/* Tabs */}
      <div style={s.tabs}>
        {[['list','Current Payouts'],['history','Monthly History']].map(([k,l])=>(
          <button key={k} style={{...s.tabBtn,...(tab===k?s.tabActive:{})}} onClick={()=>setTab(k)}>{l}</button>
        ))}
      </div>

      {tab==='list' && (<>
        {/* Filters */}
        <div style={{display:'flex',gap:'0.7rem',marginBottom:'1rem',flexWrap:'wrap',alignItems:'flex-end'}}>
          <div><label style={s.label}>Month</label>
            <select style={s.sel} value={filter.month} onChange={e=>setFilter(f=>({...f,month:e.target.value}))}>
              <option value="">All</option>{MONTHS.map(m=><option key={m}>{m}</option>)}
            </select></div>
          <div><label style={s.label}>Year</label>
            <select style={s.sel} value={filter.year} onChange={e=>setFilter(f=>({...f,year:e.target.value}))}>
              <option value="">All</option>{[2023,2024,2025,2026].map(y=><option key={y} value={y}>{y}</option>)}
            </select></div>
          <div><label style={s.label}>Status</label>
            <select style={s.sel} value={filter.status} onChange={e=>setFilter(f=>({...f,status:e.target.value}))}>
              <option value="">All</option><option value="pending">Pending</option><option value="processed">Processed</option><option value="paid">Paid</option>
            </select></div>
          {isAdmin && selected.length>0 && (
            <div style={{marginLeft:'auto',display:'flex',gap:'0.5rem'}}>
              <span style={{fontFamily:'monospace',fontSize:'0.72rem',color:'#7a7469',alignSelf:'center'}}>{selected.length} selected</span>
              <button style={{...s.btnSm,background:'#2c6fa8',color:'white',border:'none',padding:'0.4rem 0.8rem'}} onClick={()=>bulkMut.mutate({ids:selected,status:'processed'})}>Mark Processed</button>
              <button style={{...s.btnSm,background:'#4a6741',color:'white',border:'none',padding:'0.4rem 0.8rem'}} onClick={()=>bulkMut.mutate({ids:selected,status:'paid'})}>Mark Paid</button>
            </div>
          )}
        </div>

        <div style={s.tableWrap}>
          <table style={s.table}>
            <thead><tr>
              {isAdmin && <th style={s.th}><input type="checkbox" checked={allSelected} onChange={()=>setSelected(allSelected?[]:payouts.map(p=>p.id))}/></th>}
              {['Emp ID','Employee','Month/Year','Gross','Deductions','Net Pay','Mode','Status','Actions'].map(h=><th key={h} style={s.th}>{h}</th>)}
            </tr></thead>
            <tbody>
              {isLoading ? <tr><td colSpan={10} style={s.empty}>Loading…</td></tr>
              : !payouts.length ? <tr><td colSpan={10} style={s.empty}>No payouts found. Use "Generate Payouts" to create from salary records.</td></tr>
              : payouts.map((p,i)=>(
                <tr key={p.id} style={{background:i%2===0?'white':'#faf8f3'}}>
                  {isAdmin && <td style={s.td}><input type="checkbox" checked={selected.includes(p.id)} onChange={()=>toggleSelect(p.id)}/></td>}
                  <td style={{...s.td,...s.mono}}>{p.emp_id}</td>
                  <td style={s.td}><strong>{p.emp_name}</strong><div style={{fontSize:'0.7rem',color:'#7a7469'}}>{p.designation}</div></td>
                  <td style={{...s.td,...s.mono}}>{p.month} {p.year}</td>
                  <td style={{...s.td,...s.mono}}>{fmt(p.gross_amount)}</td>
                  <td style={{...s.td,...s.mono,color:'#b5451b'}}>{fmt(p.total_deductions)}</td>
                  <td style={{...s.td,...s.mono,color:'#4a6741',fontWeight:700}}>{fmt(p.net_amount)}</td>
                  <td style={s.td}><span style={s.mono}>{p.payout_mode?.replace('_',' ')}</span></td>
                  <td style={s.td}>
                    <span style={{...s.statusBadge,background:STATUS_BG[p.status],color:STATUS_COLORS[p.status],border:`1px solid ${STATUS_COLORS[p.status]}`}}>{p.status}</span>
                    {p.status==='paid'&&p.payment_date&&<div style={{fontSize:'0.68rem',color:'#7a7469',fontFamily:'monospace',marginTop:2}}>{new Date(p.payment_date).toLocaleDateString('en-IN')}</div>}
                    {p.status==='paid'&&p.reference_no&&<div style={{fontSize:'0.68rem',color:'#7a7469',fontFamily:'monospace'}}>Ref: {p.reference_no}</div>}
                  </td>
                  <td style={{...s.td,whiteSpace:'nowrap'}}>
                    {isAdmin && p.status==='pending'  && <button style={s.actBtn} onClick={()=>openStatusModal(p,'processed')}>Process</button>}
                    {isAdmin && p.status==='processed' && <button style={{...s.actBtn,background:'#4a6741',borderColor:'#4a6741'}} onClick={()=>openStatusModal(p,'paid')}>Mark Paid</button>}
                    {isAdmin && p.status==='pending'  && <button style={{...s.btnSm,borderColor:'#b5451b',color:'#b5451b',marginLeft:4}} onClick={()=>{if(window.confirm('Delete?'))delMut.mutate(p.id)}}>✕</button>}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </>)}

      {tab==='history' && (
        <div style={s.tableWrap}>
          <table style={s.table}>
            <thead><tr>{['Month','Year','Employees','Total Payout','Pending','Processed','Paid'].map(h=><th key={h} style={s.th}>{h}</th>)}</tr></thead>
            <tbody>
              {!summary?.monthlyHistory?.length ? <tr><td colSpan={7} style={s.empty}>No history yet.</td></tr>
              : summary.monthlyHistory.map((r,i)=>(
                <tr key={i} style={{background:i%2===0?'white':'#faf8f3'}}>
                  <td style={s.td}>{r.month}</td>
                  <td style={{...s.td,...s.mono}}>{r.year}</td>
                  <td style={{...s.td,...s.mono}}>{r.emp_count}</td>
                  <td style={{...s.td,...s.mono,fontWeight:600}}>{fmt(r.total_payout)}</td>
                  <td style={s.td}><span style={{...s.statusBadge,background:STATUS_BG.pending,color:STATUS_COLORS.pending,border:`1px solid ${STATUS_COLORS.pending}`}}>{r.pending_count}</span></td>
                  <td style={s.td}><span style={{...s.statusBadge,background:STATUS_BG.processed,color:STATUS_COLORS.processed,border:`1px solid ${STATUS_COLORS.processed}`}}>{r.processed_count}</span></td>
                  <td style={s.td}><span style={{...s.statusBadge,background:STATUS_BG.paid,color:STATUS_COLORS.paid,border:`1px solid ${STATUS_COLORS.paid}`}}>{r.paid_count}</span></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* GENERATE MODAL */}
      {genModal && (
        <div style={s.overlay} onClick={e=>e.target===e.currentTarget&&setGenModal(false)}>
          <div style={{...s.modal,maxWidth:400}}>
            <div style={s.modalHdr}><span style={s.modalTitle}>Generate Payouts</span><button style={s.closeBtn} onClick={()=>setGenModal(false)}><X size={18}/></button></div>
            <div style={s.modalBody}>
              <p style={{fontSize:'0.82rem',color:'#7a7469',marginBottom:'1.2rem',lineHeight:1.6}}>Creates payout records for all employees who have salary records in the selected month/year. Existing payouts will be skipped.</p>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'0.9rem',marginBottom:'1.2rem'}}>
                <div><label style={s.label}>Month *</label>
                  <select style={s.input} value={genForm.month} onChange={e=>setGenForm(p=>({...p,month:e.target.value}))}>
                    {MONTHS.map(m=><option key={m}>{m}</option>)}
                  </select></div>
                <div><label style={s.label}>Year *</label>
                  <input style={s.input} type="number" value={genForm.year} onChange={e=>setGenForm(p=>({...p,year:e.target.value}))}/></div>
              </div>
              <div style={s.modalFooter}>
                <button style={s.btnSecondary} onClick={()=>setGenModal(false)}>Cancel</button>
                <button style={s.btnPrimary} onClick={()=>genMut.mutate(genForm)}><Zap size={13}/> Generate</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* STATUS UPDATE MODAL */}
      {statusModal && (
        <div style={s.overlay} onClick={e=>e.target===e.currentTarget&&setStatusModal(null)}>
          <div style={{...s.modal,maxWidth:440}}>
            <div style={s.modalHdr}>
              <span style={s.modalTitle}>{statusModal.targetStatus==='processed'?'Mark as Processed':'Mark as Paid'}</span>
              <button style={s.closeBtn} onClick={()=>setStatusModal(null)}><X size={18}/></button>
            </div>
            <div style={s.modalBody}>
              <div style={{background:'#faf8f3',border:'1px solid #d4cfc5',borderRadius:3,padding:'0.8rem',marginBottom:'1.1rem',fontFamily:'monospace',fontSize:'0.78rem'}}>
                <strong>{statusModal.payout.emp_name}</strong> — {statusModal.payout.month} {statusModal.payout.year}<br/>
                Net Pay: <strong style={{color:'#4a6741'}}>{fmt(statusModal.payout.net_amount)}</strong>
              </div>
              {statusModal.targetStatus==='processed' && (
                <div>
                  <div><label style={s.label}>Payout Mode</label>
                    <select style={s.input} value={statusForm.payout_mode} onChange={e=>setStatusForm(p=>({...p,payout_mode:e.target.value}))}>
                      <option value="bank_transfer">Bank Transfer</option>
                      <option value="cash">Cash</option>
                      <option value="cheque">Cheque</option>
                    </select></div>
                  <div style={{marginTop:'0.8rem'}}><label style={s.label}>Remarks</label><input style={s.input} value={statusForm.remarks} onChange={e=>setStatusForm(p=>({...p,remarks:e.target.value}))} placeholder="Optional"/></div>
                </div>
              )}
              {statusModal.targetStatus==='paid' && (
                <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'0.9rem'}}>
                  <div><label style={s.label}>Payment Date *</label><input style={s.input} type="date" value={statusForm.payment_date} onChange={e=>setStatusForm(p=>({...p,payment_date:e.target.value}))} required/></div>
                  <div><label style={s.label}>Reference No. *</label><input style={s.input} value={statusForm.reference_no} onChange={e=>setStatusForm(p=>({...p,reference_no:e.target.value}))} placeholder="UTR / Cheque No." required/></div>
                </div>
              )}
              <div style={s.modalFooter}>
                <button style={s.btnSecondary} onClick={()=>setStatusModal(null)}>Cancel</button>
                <button style={{...s.btnPrimary,background: statusModal.targetStatus==='paid'?'#4a6741':'#2c6fa8',borderColor:statusModal.targetStatus==='paid'?'#4a6741':'#2c6fa8'}}
                  onClick={()=>statusMut.mutate({id:statusModal.payout.id,data:{status:statusModal.targetStatus,...statusForm}})}>
                  {statusModal.targetStatus==='processed'?'Confirm Process':'Confirm Payment'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

const s = {
  pageHeader:{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:'1.5rem',flexWrap:'wrap',gap:'1rem'},
  title:{fontFamily:"'DM Serif Display',serif",fontSize:'1.8rem',color:'#0f0e0c',margin:0},
  sub:{color:'#7a7469',fontSize:'0.78rem',fontFamily:'monospace',marginTop:2},
  statRow:{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(170px,1fr))',gap:'1rem',marginBottom:'1.5rem'},
  statCard:{background:'white',border:'1.5px solid #d4cfc5',borderRadius:4,padding:'1rem 1.2rem'},
  statLabel:{fontFamily:'monospace',fontSize:'0.65rem',textTransform:'uppercase',letterSpacing:'0.1em',color:'#7a7469',marginBottom:4},
  statVal:{fontFamily:"'DM Serif Display',serif",fontSize:'1.5rem'},
  tabs:{display:'flex',borderBottom:'2px solid #d4cfc5',marginBottom:'1.2rem'},
  tabBtn:{background:'none',border:'none',borderBottom:'3px solid transparent',padding:'0.7rem 1.4rem',fontFamily:'monospace',fontSize:'0.75rem',textTransform:'uppercase',letterSpacing:'0.08em',cursor:'pointer',color:'#7a7469',marginBottom:'-2px'},
  tabActive:{color:'#0f0e0c',borderBottomColor:'#c9a84c',background:'white'},
  sel:{padding:'0.45rem 0.7rem',border:'1.5px solid #d4cfc5',borderRadius:3,fontFamily:'monospace',fontSize:'0.78rem',background:'white'},
  tableWrap:{border:'1.5px solid #d4cfc5',borderRadius:4,overflowX:'auto'},
  table:{width:'100%',borderCollapse:'collapse',fontSize:'0.8rem'},
  th:{background:'#0f0e0c',color:'#e8d5a0',fontFamily:'monospace',fontSize:'0.62rem',textTransform:'uppercase',letterSpacing:'0.08em',padding:'0.65rem 0.9rem',textAlign:'left',whiteSpace:'nowrap'},
  td:{padding:'0.55rem 0.9rem',borderBottom:'1px solid #ede9df',verticalAlign:'middle'},
  mono:{fontFamily:'monospace',fontSize:'0.78rem'},
  statusBadge:{display:'inline-block',borderRadius:20,padding:'0.18rem 0.55rem',fontSize:'0.65rem',fontFamily:'monospace',textTransform:'uppercase',letterSpacing:'0.05em'},
  actBtn:{background:'#2c6fa8',color:'white',border:'1.5px solid #2c6fa8',borderRadius:3,padding:'0.25rem 0.65rem',fontFamily:'monospace',fontSize:'0.65rem',cursor:'pointer',textTransform:'uppercase'},
  btnSm:{background:'transparent',border:'1.5px solid #d4cfc5',borderRadius:3,padding:'0.25rem 0.4rem',cursor:'pointer'},
  btnPrimary:{display:'flex',alignItems:'center',gap:5,background:'#0f0e0c',color:'#c9a84c',border:'1.5px solid #0f0e0c',borderRadius:3,padding:'0.55rem 1.1rem',fontFamily:'monospace',fontSize:'0.72rem',textTransform:'uppercase',letterSpacing:'0.08em',cursor:'pointer'},
  btnSecondary:{background:'transparent',color:'#0f0e0c',border:'1.5px solid #d4cfc5',borderRadius:3,padding:'0.55rem 1.1rem',fontFamily:'monospace',fontSize:'0.72rem',textTransform:'uppercase',cursor:'pointer'},
  overlay:{position:'fixed',inset:0,background:'rgba(15,14,12,0.55)',zIndex:300,display:'flex',alignItems:'center',justifyContent:'center',padding:'1rem'},
  modal:{background:'white',border:'2px solid #d4cfc5',borderRadius:6,width:'100%',maxWidth:580,maxHeight:'90vh',display:'flex',flexDirection:'column',boxShadow:'0 24px 60px rgba(0,0,0,0.25)'},
  modalHdr:{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'1.2rem 1.5rem',borderBottom:'1.5px solid #d4cfc5'},
  modalTitle:{fontFamily:"'DM Serif Display',serif",fontSize:'1.15rem',color:'#0f0e0c'},
  modalBody:{padding:'1.5rem',overflowY:'auto'},
  modalFooter:{display:'flex',gap:'0.7rem',justifyContent:'flex-end',marginTop:'1.2rem'},
  closeBtn:{background:'none',border:'none',cursor:'pointer',color:'#7a7469',padding:4},
  label:{display:'block',fontFamily:'monospace',fontSize:'0.65rem',textTransform:'uppercase',letterSpacing:'0.08em',color:'#7a7469',marginBottom:'0.3rem'},
  input:{width:'100%',padding:'0.5rem 0.7rem',border:'1.5px solid #d4cfc5',borderRadius:3,fontFamily:"'DM Sans',sans-serif",fontSize:'0.85rem',boxSizing:'border-box'},
  empty:{textAlign:'center',padding:'2.5rem',color:'#7a7469',fontFamily:'monospace',fontSize:'0.8rem'},
};
