import React, { useState, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getSalary, getEmployees, upsertSalary, deleteSalary } from '../services/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Plus, Trash2, X, Calculator } from 'lucide-react';

const MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const fmt = n => '₹' + Number(n||0).toLocaleString('en-IN', {minimumFractionDigits:2,maximumFractionDigits:2});
const n = v => parseFloat(v)||0;

const BLANK_EARN = { basic:'', hra:'', conv_allowance:'', medical_allowance:'', special_allowance:'', statutory_bonus:'', consultant_fee:'', other_allowances:'', leave_encashment:'' };
const BLANK_DED  = { pf:'', pt:'', esi:'', tds:'', tds_lwf:'', gmi:'', other_deductions:'' };
const BLANK = { emp_id:'', month:'', year: new Date().getFullYear().toString(), ...BLANK_EARN, ...BLANK_DED };

export default function Salary() {
  const { isAdmin } = useAuth();
  const qc = useQueryClient();
  const [filter, setFilter] = useState({ month: '', year: '', emp_id: '' });
  const [modal, setModal] = useState(false);
  const [form, setForm] = useState(BLANK);

  const { data: records = [], isLoading } = useQuery({
    queryKey: ['salary', filter],
    queryFn: () => getSalary(filter).then(r => r.data),
  });
  const { data: employees = [] } = useQuery({
    queryKey: ['employees'],
    queryFn: () => getEmployees().then(r => r.data),
  });

  const upsertMut = useMutation({ mutationFn: upsertSalary, onSuccess: () => { toast.success('Salary saved'); setModal(false); qc.invalidateQueries({queryKey:['salary']}); }, onError: e => toast.error(e.response?.data?.error||'Error') });
  const deleteMut = useMutation({ mutationFn: deleteSalary, onSuccess: () => { toast.success('Deleted'); qc.invalidateQueries({queryKey:['salary']}); }, onError: e => toast.error(e.response?.data?.error||'Error') });

  const gross = Object.values(BLANK_EARN).reduce((a,_,i) => a + n(form[Object.keys(BLANK_EARN)[i]]), 0) ||
    (n(form.basic)+n(form.hra)+n(form.conv_allowance)+n(form.medical_allowance)+n(form.special_allowance)+n(form.statutory_bonus)+n(form.consultant_fee)+n(form.other_allowances)+n(form.leave_encashment));
  const totalDed = n(form.pf)+n(form.pt)+n(form.esi)+n(form.tds)+n(form.tds_lwf)+n(form.gmi)+n(form.other_deductions);
  const netPay   = gross - totalDed;

  const f = k => ({ value: form[k], onChange: e => setForm(p => ({...p,[k]:e.target.value})) });

  return (
    <div>
      <div style={s.pageHeader}>
        <div>
          <h1 style={s.title}>Salary Records</h1>
          <p style={s.sub}>{records.length} records{!isAdmin && ' · View only'}</p>
        </div>
        <div style={{ display:'flex', gap:'0.7rem', flexWrap:'wrap', alignItems:'center' }}>
          <select style={s.sel} value={filter.emp_id} onChange={e=>setFilter(f=>({...f,emp_id:e.target.value}))}>
            <option value="">All Employees</option>
            {employees.map(e=><option key={e.emp_id} value={e.emp_id}>{e.emp_id} – {e.name}</option>)}
          </select>
          <select style={s.sel} value={filter.month} onChange={e=>setFilter(f=>({...f,month:e.target.value}))}>
            <option value="">All Months</option>
            {MONTHS.map(m=><option key={m} value={m}>{m}</option>)}
          </select>
          <select style={s.sel} value={filter.year} onChange={e=>setFilter(f=>({...f,year:e.target.value}))}>
            <option value="">All Years</option>
            {[2023,2024,2025,2026].map(y=><option key={y} value={y}>{y}</option>)}
          </select>
          {isAdmin && <button style={s.btnPrimary} onClick={()=>{setForm(BLANK);setModal(true);}}><Plus size={14}/> Add Record</button>}
        </div>
      </div>

      <div style={s.tableWrap}>
        <table style={s.table}>
          <thead><tr>
            {['Emp ID','Name','Month','Year','Gross Earnings','Total Deductions','Net Pay', isAdmin?'Delete':''].map((h,i)=>h&&<th key={i} style={s.th}>{h}</th>)}
          </tr></thead>
          <tbody>
            {isLoading ? <tr><td colSpan={8} style={s.empty}>Loading…</td></tr>
            : !records.length ? <tr><td colSpan={8} style={s.empty}>No records found.</td></tr>
            : records.map((r,i)=>(
              <tr key={r.id} style={{background:i%2===0?'white':'#faf8f3'}}>
                <td style={{...s.td,...s.mono}}>{r.emp_id}</td>
                <td style={s.td}><strong>{r.name}</strong></td>
                <td style={s.td}>{r.month}</td>
                <td style={{...s.td,...s.mono}}>{r.year}</td>
                <td style={{...s.td,...s.mono,fontWeight:600}}>{fmt(r.gross_earnings)}</td>
                <td style={{...s.td,...s.mono,color:'#b5451b'}}>{fmt(r.total_deductions)}</td>
                <td style={{...s.td,...s.mono,color:'#4a6741',fontWeight:700}}>{fmt(r.net_pay)}</td>
                {isAdmin && <td style={s.td}><button style={{...s.btnSm,borderColor:'#b5451b',color:'#b5451b'}} onClick={()=>{if(window.confirm('Delete?'))deleteMut.mutate(r.id)}}><Trash2 size={12}/></button></td>}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Add Salary Modal */}
      {modal && (
        <div style={s.modalOverlay} onClick={e=>e.target===e.currentTarget&&setModal(false)}>
          <div style={s.modal}>
            <div style={s.modalHeader}>
              <div style={s.modalTitle}>Add / Update Salary Record</div>
              <button style={s.closeBtn} onClick={()=>setModal(false)}><X size={18}/></button>
            </div>
            <div style={{overflowY:'auto',maxHeight:'calc(90vh - 130px)',padding:'0 1.5rem 1.5rem'}}>
              {/* Employee + Period */}
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:'0.8rem',marginBottom:'1.2rem'}}>
                <div>
                  <label style={s.label}>Employee *</label>
                  <select style={s.input} value={form.emp_id} onChange={e=>setForm(p=>({...p,emp_id:e.target.value}))} required>
                    <option value="">Select</option>
                    {employees.map(e=><option key={e.emp_id} value={e.emp_id}>{e.emp_id} – {e.name}</option>)}
                  </select>
                </div>
                <div>
                  <label style={s.label}>Month *</label>
                  <select style={s.input} value={form.month} onChange={e=>setForm(p=>({...p,month:e.target.value}))} required>
                    <option value="">Select</option>
                    {MONTHS.map(m=><option key={m}>{m}</option>)}
                  </select>
                </div>
                <div>
                  <label style={s.label}>Year *</label>
                  <input style={s.input} type="number" min="2020" max="2030" {...f('year')} required/>
                </div>
              </div>

              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'1.2rem'}}>
                {/* Earnings */}
                <div>
                  <div style={s.secTitle}>Earnings</div>
                  {[['Basic','basic'],['HRA','hra'],['Conv Allowance','conv_allowance'],['Medical Allowance','medical_allowance'],['Special Allowance','special_allowance'],['Statutory Bonus','statutory_bonus'],['Consultant Fee','consultant_fee'],['Other Allowances','other_allowances'],['Leave Encashment','leave_encashment']].map(([lbl,key])=>(
                    <div key={key} style={{marginBottom:'0.6rem'}}>
                      <label style={s.label}>{lbl}</label>
                      <input style={s.input} type="number" min="0" step="0.01" {...f(key)} placeholder="0"/>
                    </div>
                  ))}
                </div>
                {/* Deductions */}
                <div>
                  <div style={s.secTitle}>Deductions</div>
                  {[['PF','pf'],['PT (Prof. Tax)','pt'],['ESI','esi'],['TDS','tds'],['TDS LWF','tds_lwf'],['GMI','gmi'],['Other Deductions','other_deductions']].map(([lbl,key])=>(
                    <div key={key} style={{marginBottom:'0.6rem'}}>
                      <label style={s.label}>{lbl}</label>
                      <input style={s.input} type="number" min="0" step="0.01" {...f(key)} placeholder="0"/>
                    </div>
                  ))}
                  {/* Live calc */}
                  <div style={{background:'#0f0e0c',borderRadius:4,padding:'1rem',marginTop:'1rem'}}>
                    <div style={{display:'flex',justifyContent:'space-between',color:'rgba(245,242,235,0.6)',fontSize:'0.75rem',marginBottom:'0.5rem'}}><span>Gross Earnings</span><span style={{fontFamily:'monospace',color:'#e8d5a0'}}>{fmt(gross)}</span></div>
                    <div style={{display:'flex',justifyContent:'space-between',color:'rgba(245,242,235,0.6)',fontSize:'0.75rem',marginBottom:'0.5rem'}}><span>Total Deductions</span><span style={{fontFamily:'monospace',color:'#e07050'}}>{fmt(totalDed)}</span></div>
                    <div style={{display:'flex',justifyContent:'space-between',borderTop:'1px solid rgba(255,255,255,0.12)',paddingTop:'0.5rem',marginTop:'0.5rem'}}><span style={{color:'#c9a84c',fontWeight:600,fontSize:'0.8rem'}}>Net Pay</span><span style={{fontFamily:'monospace',color:'#c9a84c',fontWeight:700,fontSize:'0.95rem'}}>{fmt(netPay)}</span></div>
                  </div>
                </div>
              </div>

              <div style={{display:'flex',gap:'0.7rem',justifyContent:'flex-end',marginTop:'1rem'}}>
                <button style={s.btnSecondary} onClick={()=>setModal(false)}>Cancel</button>
                <button style={s.btnPrimary} onClick={()=>upsertMut.mutate(form)}>Save Record</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

const s = {
  pageHeader:{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:'1.5rem',flexWrap:'wrap',gap:'1rem'},
  title:{fontFamily:"'DM Serif Display',serif",fontSize:'1.8rem',color:'#0f0e0c',margin:0},
  sub:{color:'#7a7469',fontSize:'0.78rem',fontFamily:'monospace',marginTop:2},
  sel:{padding:'0.45rem 0.7rem',border:'1.5px solid #d4cfc5',borderRadius:3,fontFamily:'monospace',fontSize:'0.78rem',background:'white'},
  btnPrimary:{display:'flex',alignItems:'center',gap:5,background:'#0f0e0c',color:'#c9a84c',border:'1.5px solid #0f0e0c',borderRadius:3,padding:'0.55rem 1.1rem',fontFamily:'monospace',fontSize:'0.72rem',textTransform:'uppercase',letterSpacing:'0.08em',cursor:'pointer'},
  btnSecondary:{background:'transparent',color:'#0f0e0c',border:'1.5px solid #d4cfc5',borderRadius:3,padding:'0.55rem 1.1rem',fontFamily:'monospace',fontSize:'0.72rem',textTransform:'uppercase',letterSpacing:'0.08em',cursor:'pointer'},
  btnSm:{background:'transparent',border:'1.5px solid #d4cfc5',borderRadius:3,padding:'0.25rem 0.4rem',cursor:'pointer'},
  tableWrap:{border:'1.5px solid #d4cfc5',borderRadius:4,overflowX:'auto'},
  table:{width:'100%',borderCollapse:'collapse',fontSize:'0.8rem'},
  th:{background:'#0f0e0c',color:'#e8d5a0',fontFamily:'monospace',fontSize:'0.62rem',textTransform:'uppercase',letterSpacing:'0.08em',padding:'0.65rem 0.9rem',textAlign:'left',whiteSpace:'nowrap'},
  td:{padding:'0.55rem 0.9rem',borderBottom:'1px solid #ede9df',verticalAlign:'middle'},
  mono:{fontFamily:'monospace',fontSize:'0.78rem'},
  empty:{textAlign:'center',padding:'2.5rem',color:'#7a7469',fontFamily:'monospace',fontSize:'0.8rem'},
  modalOverlay:{position:'fixed',inset:0,background:'rgba(15,14,12,0.55)',zIndex:300,display:'flex',alignItems:'center',justifyContent:'center',padding:'1rem'},
  modal:{background:'white',border:'2px solid #d4cfc5',borderRadius:6,width:'100%',maxWidth:720,maxHeight:'90vh',display:'flex',flexDirection:'column',boxShadow:'0 24px 60px rgba(0,0,0,0.25)'},
  modalHeader:{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'1.2rem 1.5rem',borderBottom:'1.5px solid #d4cfc5',flexShrink:0},
  modalTitle:{fontFamily:"'DM Serif Display',serif",fontSize:'1.2rem',color:'#0f0e0c'},
  closeBtn:{background:'none',border:'none',cursor:'pointer',color:'#7a7469',padding:4},
  label:{display:'block',fontFamily:'monospace',fontSize:'0.65rem',textTransform:'uppercase',letterSpacing:'0.08em',color:'#7a7469',marginBottom:'0.25rem'},
  input:{width:'100%',padding:'0.5rem 0.7rem',border:'1.5px solid #d4cfc5',borderRadius:3,fontFamily:"'DM Sans',sans-serif",fontSize:'0.85rem',boxSizing:'border-box',outline:'none'},
  secTitle:{fontFamily:'monospace',fontSize:'0.65rem',textTransform:'uppercase',letterSpacing:'0.1em',color:'#c9a84c',marginBottom:'0.8rem',paddingBottom:'0.4rem',borderBottom:'1px solid #e8d5a0'},
};
