import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

export default function Login() {
  const { login } = useAuth();
  const navigate  = useNavigate();
  const [form, setForm] = useState({ username: '', password: '' });
  const [loading, setLoading] = useState(false);

  const handle = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form);
      toast.success('Welcome back!');
      navigate('/');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        <div style={styles.logo}>⬡ <span style={styles.logoSpan}>Payroll</span>Manager</div>
        <p style={styles.sub}>Sign in to continue</p>

        <form onSubmit={handle}>
          <div style={styles.group}>
            <label style={styles.label}>Username or Email</label>
            <input
              style={styles.input}
              type="text"
              value={form.username}
              onChange={e => setForm(f => ({ ...f, username: e.target.value }))}
              placeholder="admin"
              required
              autoFocus
            />
          </div>
          <div style={styles.group}>
            <label style={styles.label}>Password</label>
            <input
              style={styles.input}
              type="password"
              value={form.password}
              onChange={e => setForm(f => ({ ...f, password: e.target.value }))}
              placeholder="••••••••"
              required
            />
          </div>
          <button style={{ ...styles.btn, opacity: loading ? 0.7 : 1 }} disabled={loading}>
            {loading ? 'Signing in…' : 'Sign In →'}
          </button>
        </form>

        <div style={styles.hint}>
          <strong>Demo credentials</strong><br />
          Admin: <code>admin</code> / <code>Admin@123</code><br />
          User: <code>viewer</code> / <code>User@123</code>
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: { minHeight: '100vh', background: '#f5f2eb', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: "'DM Sans', sans-serif" },
  card: { background: 'white', border: '1.5px solid #d4cfc5', borderRadius: 6, padding: '2.5rem', width: '100%', maxWidth: 400, boxShadow: '0 8px 32px rgba(0,0,0,0.08)' },
  logo: { fontFamily: "'DM Serif Display', serif", fontSize: '1.6rem', marginBottom: '0.3rem', color: '#0f0e0c' },
  logoSpan: { color: '#c9a84c' },
  sub: { color: '#7a7469', fontSize: '0.82rem', fontFamily: "'DM Mono', monospace", marginBottom: '1.8rem' },
  group: { marginBottom: '1rem' },
  label: { display: 'block', fontFamily: "'DM Mono', monospace", fontSize: '0.68rem', textTransform: 'uppercase', letterSpacing: '0.08em', color: '#7a7469', marginBottom: '0.35rem' },
  input: { width: '100%', padding: '0.6rem 0.8rem', border: '1.5px solid #d4cfc5', borderRadius: 3, fontFamily: "'DM Sans', sans-serif", fontSize: '0.9rem', boxSizing: 'border-box', outline: 'none' },
  btn: { width: '100%', padding: '0.75rem', background: '#0f0e0c', color: '#c9a84c', border: 'none', borderRadius: 3, fontFamily: "'DM Mono', monospace", fontSize: '0.8rem', textTransform: 'uppercase', letterSpacing: '0.1em', cursor: 'pointer', marginTop: '0.5rem' },
  hint: { marginTop: '1.5rem', background: '#f5f2eb', borderRadius: 4, padding: '0.9rem', fontSize: '0.75rem', color: '#7a7469', fontFamily: "'DM Mono', monospace", lineHeight: 1.8 },
};
