import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import {
  Users, DollarSign, BarChart2, LogOut, Shield,
  Menu, X, Download, Upload, Settings, Gift, CreditCard, FileX, BarChart
} from 'lucide-react';

const NAV = [
  { to: '/',            label: 'Dashboard',   icon: BarChart2,  roles: ['admin','user'] },
  { to: '/employees',   label: 'Employees',   icon: Users,      roles: ['admin','user'] },
  { to: '/salary',      label: 'Salary',      icon: DollarSign, roles: ['admin','user'] },
  { to: '/allowances',  label: 'Allowances',  icon: Gift,       roles: ['admin','user'] },
  { to: '/payout',      label: 'Payout',      icon: CreditCard, roles: ['admin','user'] },
  { to: '/fnf',         label: 'F&F',         icon: FileX,      roles: ['admin','user'] },
  { to: '/reports',     label: 'Reports',     icon: BarChart,   roles: ['admin','user'] },
  { to: '/export',      label: 'Export',      icon: Download,   roles: ['admin','user'] },
  { to: '/import',      label: 'Import',      icon: Upload,     roles: ['admin'] },
  { to: '/users',       label: 'Users',       icon: Settings,   roles: ['admin'] },
];

export default function Layout({ children }) {
  const { user, logout, isAdmin } = useAuth();
  const navigate  = useNavigate();
  const [open, setOpen] = useState(false);

  const doLogout = () => { logout(); navigate('/login'); };

  return (
    <div style={s.shell}>
      {/* Sidebar */}
      <aside style={{ ...s.sidebar, transform: open || window.innerWidth > 768 ? 'translateX(0)' : 'translateX(-100%)' }}>
        <div style={s.sideTop}>
          <div style={s.logo}>⬡ <span style={{ color: '#c9a84c' }}>Payroll</span>Mgr</div>
          <div style={s.roleChip}>
            <Shield size={10} />
            <span>{isAdmin ? 'Admin' : 'Viewer'}</span>
          </div>
        </div>

        <nav style={s.nav}>
          {NAV.filter(n => n.roles.includes(user?.role)).map(n => (
            <NavLink key={n.to} to={n.to} end={n.to==='/'} style={({ isActive }) => ({
              ...s.navLink, ...(isActive ? s.navActive : {})
            })} onClick={() => setOpen(false)}>
              <n.icon size={15} />
              {n.label}
            </NavLink>
          ))}
        </nav>

        <div style={s.sideBottom}>
          <div style={s.userInfo}>
            <div style={s.avatar}>{user?.username?.[0]?.toUpperCase()}</div>
            <div>
              <div style={{ fontSize: '0.8rem', fontWeight: 600 }}>{user?.username}</div>
              <div style={{ fontSize: '0.68rem', color: '#7a7469', fontFamily: 'monospace' }}>{user?.role}</div>
            </div>
          </div>
          <button style={s.logoutBtn} onClick={doLogout}>
            <LogOut size={14} /> Sign Out
          </button>
        </div>
      </aside>

      {/* Main area */}
      <div style={s.main}>
        <header style={s.topbar}>
          <button style={s.hamburger} onClick={() => setOpen(o => !o)}>
            {open ? <X size={20} /> : <Menu size={20} />}
          </button>
          <div style={s.topbarRight}>
            {!isAdmin && (
              <span style={s.viewerBadge}>👁 View Only Mode</span>
            )}
          </div>
        </header>
        <div style={s.content}>{children}</div>
      </div>

      {open && <div style={s.overlay} onClick={() => setOpen(false)} />}
    </div>
  );
}

const s = {
  shell: { display: 'flex', minHeight: '100vh', fontFamily: "'DM Sans', sans-serif", background: '#f5f2eb' },
  sidebar: { width: 220, background: '#0f0e0c', display: 'flex', flexDirection: 'column', flexShrink: 0, position: 'sticky', top: 0, height: '100vh', zIndex: 200, transition: 'transform 0.25s' },
  sideTop: { padding: '1.4rem 1.2rem 1rem', borderBottom: '1px solid rgba(255,255,255,0.08)' },
  logo: { fontFamily: "'DM Serif Display', serif", fontSize: '1.15rem', color: '#f5f2eb', marginBottom: '0.5rem' },
  roleChip: { display: 'inline-flex', alignItems: 'center', gap: 4, background: 'rgba(201,168,76,0.15)', border: '1px solid rgba(201,168,76,0.3)', color: '#c9a84c', borderRadius: 20, padding: '0.18rem 0.55rem', fontSize: '0.62rem', fontFamily: 'monospace', textTransform: 'uppercase', letterSpacing: '0.08em' },
  nav: { flex: 1, padding: '0.8rem 0.6rem', display: 'flex', flexDirection: 'column', gap: 2 },
  navLink: { display: 'flex', alignItems: 'center', gap: 9, color: 'rgba(245,242,235,0.55)', padding: '0.55rem 0.8rem', borderRadius: 3, textDecoration: 'none', fontSize: '0.82rem', fontWeight: 500, transition: 'all 0.15s' },
  navActive: { background: 'rgba(201,168,76,0.12)', color: '#c9a84c', borderLeft: '3px solid #c9a84c', paddingLeft: 'calc(0.8rem - 3px)' },
  sideBottom: { padding: '1rem 1.2rem', borderTop: '1px solid rgba(255,255,255,0.08)' },
  userInfo: { display: 'flex', alignItems: 'center', gap: '0.7rem', marginBottom: '0.8rem' },
  avatar: { width: 32, height: 32, borderRadius: '50%', background: '#c9a84c', color: '#0f0e0c', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, fontSize: '0.85rem', flexShrink: 0 },
  logoutBtn: { width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6, background: 'rgba(181,69,27,0.12)', border: '1px solid rgba(181,69,27,0.3)', color: '#e07050', borderRadius: 3, padding: '0.45rem', fontSize: '0.75rem', fontFamily: 'monospace', cursor: 'pointer', textTransform: 'uppercase', letterSpacing: '0.08em' },
  main: { flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0 },
  topbar: { background: 'white', borderBottom: '1.5px solid #d4cfc5', padding: '0.7rem 1.5rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between', position: 'sticky', top: 0, zIndex: 100 },
  hamburger: { background: 'none', border: 'none', cursor: 'pointer', display: 'none', padding: 4 },
  topbarRight: { display: 'flex', alignItems: 'center', gap: '1rem' },
  viewerBadge: { background: '#fdf3e7', border: '1px solid #f0d080', color: '#7a5c10', borderRadius: 20, padding: '0.2rem 0.7rem', fontSize: '0.72rem', fontFamily: 'monospace' },
  content: { padding: '1.8rem 2rem', flex: 1 },
  overlay: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', zIndex: 199 },
};
