const MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const SEP_TYPES = ['resignation','termination','retirement','absconding'];
const fmtN = n => '₹' + Number(n||0).toLocaleString('en-IN', { minimumFractionDigits:2 });
const fmtK = n => { const v=Number(n||0); if(v>=1e7) return '₹'+(v/1e7).toFixed(1)+'Cr'; if(v>=1e5) return '₹'+(v/1e5).toFixed(1)+'L'; if(v>=1e3) return '₹'+(v/1e3).toFixed(1)+'K'; return '₹'+v; };

const REPORT_TYPES = [
  { key:'payroll',    label:'Payroll Report',   desc:'Full salary breakdown per employee per period' },
  { key:'payout',     label:'Payout Report',    desc:'Disbursement status, payment dates & references' },
  { key:'fnf',        label:'F&F Report',       desc:'Full & Final settlement details for separated employees' },
  { key:'allowances', label:'Allowances Report', desc:'Active allowance assignments with computed amounts' },
];

function exportCSV(data, filename, columns) {
  if (!data?.length) return;
  const header = columns.map(c=>c.label).join(',');
  const rows   = data.map(row => columns.map(c=>{
    const val = c.fn ? c.fn(row) : (row[c.key]??'');
    return `"${String(val).replace(/"/g,'""')}"`;
  }).join(','));
  const blob = new Blob([header+'\n'+rows.join('\n')], { type:'text/csv' });
  const a = document.createElement('a'); a.href = URL.createObjectURL(blob);
  a.download = filename; a.click();
}

